const clients = [
  { name: 'Alfa Construction Inc.', ghlKey: 'YOUR_GHL_KEY', email: 'info@alfapaintingcarpentry.com', site: 'https://www.alfapaintingcarpentry.com/' },
  { name: 'Wolfs Siding Inc', ghlKey: 'YOUR_GHL_KEY', email: 'info@wolfs-siding.com', site: 'https://wolfs-siding.com/' },
  { name: 'RS Development Group', ghlKey: 'YOUR_GHL_KEY', email: 'info@rs-developmentgroup.com', site: 'https://rs-developmentgroup.com/' },
  { name: 'Mass HVAC', ghlKey: 'YOUR_GHL_KEY', email: 'info@masshvac.net', site: 'https://masshvac.net/' },
  { name: 'Maia Construction Inc', ghlKey: 'YOUR_GHL_KEY', email: 'contact@maiaconstruction.com', site: 'https://maiaconstruction.com/' },
  { name: 'JH Painting Services', ghlKey: 'YOUR_GHL_KEY', email: 'contact@jhpaintingservices.com', site: 'https://jhpaintingservices.com/' },
  { name: 'Dorys Cleaning Services', ghlKey: 'YOUR_GHL_KEY', email: 'contact@doryscleaningservices.com', site: 'https://doryscleaningservices.com/' }
];
const TEST_EMAIL = 'galaxyinfomkt@gmail.com';
clients.forEach(c => { c.originalEmail = c.email; c.email = TEST_EMAIL; });
return clients.map(c => ({ json: c }));

// Set date range for GSC queries
const now = new Date();
const thirtyAgo = new Date(now.getTime() - 30*24*60*60*1000);
return [{ json: {
  ...$json,
  startDate: thirtyAgo.toISOString().split('T')[0],
  endDate: now.toISOString().split('T')[0]
}}];

const client = $('Datas').item.json;
const allContacts = $('GHL - Contatos').item.json.contacts || [];
const gscQueries = $('GSC - Top Queries').item.json || {};
const gscTotals = $('GSC - Totais').item.json || {};

// 30 day filter
const now = new Date();
const thirtyAgoMs = now.getTime() - 30*24*60*60*1000;
const last30 = allContacts.filter(c => c.dateAdded && new Date(c.dateAdded).getTime() >= thirtyAgoMs);

// Sources
const sources30d = {};
last30.forEach(c => { const s = c.source || c.tags?.[0] || 'Direto'; sources30d[s] = (sources30d[s]||0)+1; });
const topSources = Object.entries(sources30d).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([k,v])=>k+' ('+v+')').join(', ') || 'Nenhum';

// GSC data
let impressions = 0, clicks = 0, avgCtr = 0, avgPos = 0;
const totalsRows = gscTotals.rows || [];
if (totalsRows.length > 0) {
  totalsRows.forEach(r => { impressions += r.impressions; clicks += r.clicks; });
  avgCtr = impressions > 0 ? ((clicks/impressions)*100).toFixed(2) : 0;
  avgPos = (totalsRows.reduce((s,r)=>s+r.position,0) / totalsRows.length).toFixed(1);
}
const queriesRows = gscQueries.rows || [];
const topQueries = queriesRows.slice(0,5).map(r => r.keys[0] + ' (' + r.clicks + ' cliques, ' + r.impressions + ' impressoes)').join('; ') || 'Dados indisponiveis';

const hasGscData = impressions > 0 || clicks > 0;
const gscStatus = hasGscData ? '' : ' (site nao cadastrado no Search Console ou sem dados)';

// Dates in PT
const mesesPT = ['janeiro','fevereiro','marco','abril','maio','junho','julho','agosto','setembro','outubro','novembro','dezembro'];
const monthName = mesesPT[now.getMonth()] + ' de ' + now.getFullYear();
const startDt = new Date(thirtyAgoMs);
const startFmt = startDt.getDate() + '/' + (startDt.getMonth()+1) + '/' + startDt.getFullYear();
const endFmt = now.getDate() + '/' + (now.getMonth()+1) + '/' + now.getFullYear();
const period = startFmt + ' a ' + endFmt;

// AI prompt
const prompt = 'IMPORTANTE: Escreva APENAS em portugues brasileiro. NADA em ingles.\n\nVoce e redator da Galaxy IT & Marketing escrevendo relatorio mensal para o cliente.\n\n=== DADOS DO CLIENTE ===\nCliente: ' + client.name + '\nSite: ' + client.site + '\nPeriodo: ' + period + '\n\n=== LEADS (GoHighLevel) ===\n- Novos leads nos ultimos 30 dias: ' + last30.length + '\n- Fontes dos leads: ' + topSources + '\n- Base historica: ' + allContacts.length + '\n\n=== SITE (Google Search Console) ===' + gscStatus + '\n- Impressoes no Google: ' + impressions + '\n- Cliques: ' + clicks + '\n- CTR medio: ' + avgCtr + '%\n- Posicao media: ' + avgPos + '\n- Top palavras-chave: ' + topQueries + '\n\n=== ESTRUTURA DO RELATORIO (em portugues) ===\n1. "Ola, equipe da ' + client.name + '!"\n2. Destaques do mes com os numeros reais (leads novos, impressoes, cliques)\n3. Analise do site no Google (se tiver dados reais)\n4. Analise das fontes de leads\n5. Uma recomendacao acionavel baseada nos dados\n6. Encerre: "Abracos, Equipe Galaxy IT & Marketing"\n\nREGRAS:\n- TUDO em portugues brasileiro\n- Use os numeros REAIS acima, nao invente\n- Se GSC estiver indisponivel, mencione que esta aguardando configuracao\n- Maximo 250 palavras\n- Tom profissional e amigavel';

const body = {
  model: 'llama-3.3-70b-versatile',
  messages: [
    { role: 'system', content: 'Voce escreve APENAS em portugues brasileiro. Nunca use ingles.' },
    { role: 'user', content: prompt }
  ],
  max_tokens: 800,
  temperature: 0.5
};

return [{ json: {
  ...client,
  newContacts: last30.length,
  totalHistorical: allContacts.length,
  topSources,
  impressions, clicks, avgCtr, avgPos, topQueries, hasGscData,
  monthName, period,
  aiBody: JSON.stringify(body)
}}];
